import { useCallback, useEffect, useId, useRef } from "react";
import { gsap } from "gsap";

// ===================================================================
// The scene IS the reference artwork, rigged as a cutout puppet:
// background (swan inpainted out), body, neck, head, and two lotus
// layers cut from the source image. Joint rule that keeps it clean:
// TOP layers (head, neck) are cut EXACTLY to their zone; only the
// layer UNDERNEATH extends ~18px into the joint. So rotating a part
// never drags duplicated pixels around, and the under-layer fills in.
// No palette quantization anywhere -> no dither grain on the swan.
// Mask v2: widened HSV thresholds (recovers highlight facets incl. the
// crown), ALL interior holes filled (was ~5k transparent pinhole px),
// boundary gaussian-smoothed; inpainted water behind the swan is
// blurred so motion reveals calm water, never smear.
// Layer bitmaps are downscaled 72% (still oversampled at the 480px
// stage); placement coords are original reference pixels via
// translate(-114.4,-114.4) scale(1.2). Global pivots (=local*1.2-114.4):
//   neck base  (300,690) -> "246 714"
//   head joint (345,405) -> "300 372"
//   raisedWing (470,635) -> "450 648"
// Motion is deliberately subtle: raster puppets read best under ~2-4deg.
// ===================================================================

const BG =
  "data:image/jpeg;base64,";
const BODY =
  "data:image/png;base64,";
const NECK =
  "data:image/png;base64,";
const HEAD =
  "data:image/png;base64,";
const LOT1 =
  "data:image/png;base64,";
const LOT2 =
  "data:image/png;base64,";

function SwanAnimation({ inline = false }) {
  const sceneRef = useRef(null);
  const floatTweenRef = useRef(null);
  const neckTweenRef = useRef(null);
  const headTweenRef = useRef(null);
  const poseTimelineRef = useRef(null);

  const clipId = useId().replace(/:/g, "");

  const getSwanParts = useCallback(() => {
    const svg = sceneRef.current;
    if (!svg) return null;

    return {
      swan: svg.querySelector("#swan-action"),
      neck: svg.querySelector("#neck-action"),
      head: svg.querySelector("#head-action"),
    };
  }, []);

  const pauseIdleMotion = useCallback(() => {
    floatTweenRef.current?.pause();
    neckTweenRef.current?.pause();
    headTweenRef.current?.pause();
  }, []);

  const resumeIdleMotion = useCallback(() => {
    floatTweenRef.current?.play();
    neckTweenRef.current?.play();
    headTweenRef.current?.play();
  }, []);

  const idle = useCallback(() => {
    const parts = getSwanParts();
    if (!parts) return;

    poseTimelineRef.current?.kill();
    poseTimelineRef.current = gsap.timeline({
      defaults: {
        duration: 0.75,
        ease: "sine.out",
        overwrite: "auto",
      },
      onComplete: resumeIdleMotion,
    });

    poseTimelineRef.current
      .to(parts.swan, { y: 0 }, 0)
      .to(parts.neck, { rotation: 0, svgOrigin: "246 714" }, 0)
      .to(parts.head, { rotation: 0, svgOrigin: "300 372" }, 0);
  }, [getSwanParts, resumeIdleMotion]);

  const alertState = useCallback(() => {
    const parts = getSwanParts();
    if (!parts) return;

    pauseIdleMotion();
    poseTimelineRef.current?.kill();
    poseTimelineRef.current = gsap.timeline({
      defaults: {
        duration: 0.6,
        ease: "power2.out",
        overwrite: "auto",
      },
    });

    poseTimelineRef.current
      .to(parts.swan, { y: -9 }, 0)
      .to(parts.neck, { rotation: 1.1, svgOrigin: "246 714" }, 0)
      .to(parts.head, { rotation: 1.8, svgOrigin: "300 372" }, 0);
  }, [getSwanParts, pauseIdleMotion]);

  useEffect(() => {
    const svg = sceneRef.current;
    if (!svg) return undefined;

    const context = gsap.context(() => {
      // Gentle swan motion. The artwork remains calm and logo-like.
      floatTweenRef.current = gsap.to("#swan-idle", {
        y: -7,
        duration: 3.8,
        ease: "sine.inOut",
        repeat: -1,
        yoyo: true,
      });

      neckTweenRef.current = gsap.to("#neck-idle", {
        rotation: 0.5,
        svgOrigin: "246 714",
        duration: 4.6,
        ease: "sine.inOut",
        repeat: -1,
        yoyo: true,
      });

      headTweenRef.current = gsap.to("#head-idle", {
        rotation: 1,
        svgOrigin: "300 372",
        duration: 3.9,
        ease: "sine.inOut",
        repeat: -1,
        yoyo: true,
        delay: 0.45,
      });

      // Swan ripples: slow and low contrast so they read as water, not UI.
      gsap.utils.toArray(".swan-ripple").forEach((ripple, index) => {
        gsap.fromTo(
          ripple,
          {
            scaleX: 0.93,
            scaleY: 0.9,
            opacity: 0.16,
            transformOrigin: "50% 50%",
            transformBox: "fill-box",
          },
          {
            scaleX: 1.11,
            scaleY: 1.05,
            opacity: 0,
            duration: 5.6 + index * 0.8,
            repeat: -1,
            ease: "power1.out",
            delay: index * 1.8,
          }
        );
      });

      // The extracted lotus assets contain only the blossoms; their stems
      // remain painted into the background. Keep the bottom centre locked to
      // the stem and use a gentle bloom/sway instead of translating the flower.
      const lotusMotion = [
        {
          rotation: 0.2,
          skewX: 0.6,
          scaleX: 1.022,
          scaleY: 0.988,
          duration: 3.9,
          delay: 0,
        },
        {
          rotation: -0.15,
          skewX: -0.46,
          scaleX: 1.017,
          scaleY: 0.992,
          duration: 4.7,
          delay: -1.8,
        },
      ];

      gsap.utils.toArray(".lotus-layer").forEach((lotus, index) => {
        const motion = lotusMotion[index] ?? lotusMotion[0];

        gsap.set(lotus, {
          x: 0,
          y: 0,
          rotation: 0,
          skewX: 0,
          scaleX: 1,
          scaleY: 1,
          transformOrigin: "50% 100%",
          transformBox: "fill-box",
        });

        gsap.timeline({
          repeat: -1,
          delay: motion.delay,
          defaults: { ease: "sine.inOut" },
        })
          .to(lotus, {
            rotation: motion.rotation,
            skewX: motion.skewX,
            scaleX: motion.scaleX,
            scaleY: motion.scaleY,
            duration: motion.duration,
          })
          .to(lotus, {
            rotation: -motion.rotation * 0.82,
            skewX: -motion.skewX * 0.82,
            scaleX: 1.006,
            scaleY: 1.004,
            duration: motion.duration * 1.08,
          })
          .to(lotus, {
            rotation: 0,
            skewX: 0,
            scaleX: 1,
            scaleY: 1,
            duration: motion.duration * 0.78,
          });
      });

      // Small ripples beneath the background lotuses make the floating motion
      // readable without exaggerating the flowers themselves.
      gsap.utils.toArray(".lotus-ripple").forEach((ripple, index) => {
        gsap.fromTo(
          ripple,
          {
            scaleX: 0.82,
            scaleY: 0.9,
            opacity: index === 0 ? 0.15 : 0.11,
            transformOrigin: "50% 50%",
            transformBox: "fill-box",
          },
          {
            scaleX: 1.16,
            scaleY: 1.04,
            opacity: 0,
            duration: index === 0 ? 4.8 : 5.6,
            repeat: -1,
            ease: "power1.out",
            delay: index * 1.9,
          }
        );
      });
    }, svg);

    return () => {
      poseTimelineRef.current?.kill();
      context.revert();

      floatTweenRef.current = null;
      neckTweenRef.current = null;
      headTweenRef.current = null;
      poseTimelineRef.current = null;
    };
  }, []);

  const svgStage = (
    <section
      style={{
        width: "min(92vw, 480px)",
        aspectRatio: "1 / 1",
        borderRadius: "50%",
        background: "rgba(6, 22, 40, 0.5)",
        boxShadow:
          "0 28px 90px rgba(0, 0, 0, 0.42), inset 0 0 0 1px rgba(130, 205, 230, 0.14)",
        overflow: "hidden",
      }}
    >
      <svg
        ref={sceneRef}
        viewBox="0 0 1000 1000"
        role="img"
        aria-label="Animated blue swan floating on a lotus lake"
        style={{
          width: "100%",
          height: "100%",
          display: "block",
          userSelect: "none",
        }}
        onMouseEnter={alertState}
        onMouseLeave={idle}
      >
        <style>{`
          .lotus-layer,
          .lotus-ripple,
          .swan-ripple {
            transform-box: fill-box;
            will-change: transform;
          }

          .lotus-layer {
            transform-origin: 50% 100%;
          }

          .lotus-ripple,
          .swan-ripple {
            transform-origin: 50% 50%;
          }
        `}</style>

        <defs>
          <clipPath id={clipId}>
            <circle cx="500" cy="500" r="468" />
          </clipPath>
        </defs>

        <g clipPath={`url(#${clipId})`}>
          <g transform="translate(-114.4 -114.4) scale(1.2)">
            <image href={BG} x="0" y="0" width="1024" height="1024" />

            <g
              fill="none"
              stroke="#eaf6f0"
              strokeWidth="2.5"
              opacity="0.3"
              pointerEvents="none"
            >
              <ellipse
                className="swan-ripple"
                cx="520"
                cy="778"
                rx="250"
                ry="20"
              />
              <ellipse
                className="swan-ripple"
                cx="515"
                cy="789"
                rx="160"
                ry="13"
              />
            </g>

            <g
              fill="none"
              stroke="#e9fbf4"
              strokeWidth="1.5"
              pointerEvents="none"
            >
              <ellipse
                className="lotus-ripple"
                cx="820"
                cy="467"
                rx="58"
                ry="5"
              />
              <ellipse
                className="lotus-ripple"
                cx="564"
                cy="429"
                rx="39"
                ry="3.5"
              />
            </g>

            <g className="lotus-layer" pointerEvents="none">
              <image
                href={LOT1}
                x="732"
                y="358"
                width="177"
                height="115"
              />
            </g>

            <g className="lotus-layer" pointerEvents="none">
              <image
                href={LOT2}
                x="504"
                y="365"
                width="121"
                height="67"
              />
            </g>

            <g id="swan-action">
              <g id="swan-idle">
                <g id="body">
                  <image
                    href={BODY}
                    x="215"
                    y="380"
                    width="621"
                    height="387"
                  />
                </g>

                <g id="neck-action">
                  <g id="neck-idle">
                    <g id="neck">
                      <image
                        href={NECK}
                        x="233"
                        y="340"
                        width="218"
                        height="331"
                      />
                    </g>

                    <g id="head-action">
                      <g id="head-idle">
                        <image
                          href={HEAD}
                          x="253"
                          y="326"
                          width="152"
                          height="109"
                        />
                      </g>
                    </g>
                  </g>
                </g>
              </g>
            </g>
          </g>
        </g>

        <circle
          cx="500"
          cy="500"
          r="468"
          fill="none"
          stroke="#16324f"
          strokeWidth="9"
          pointerEvents="none"
        />
      </svg>
    </section>
  );

  if (inline) return svgStage;

  return (
    <div
      style={{
        minHeight: "100vh",
        display: "grid",
        placeItems: "center",
        background:
          "radial-gradient(circle at 50% 18%, rgba(95, 188, 211, 0.18), transparent 38%), linear-gradient(180deg, #0a1c30, #123048)",
        overflow: "hidden",
      }}
    >
      <div
        style={{
          width: "min(94vw, 980px)",
          display: "grid",
          gap: 18,
          justifyItems: "center",
        }}
      >
        <div
          style={{
            fontSize: 12,
            letterSpacing: "0.28em",
            textTransform: "uppercase",
            opacity: 0.78,
            color: "#d4ecf5",
          }}
        >
          Blue Swan · Lotus Lake · Rive-Style
        </div>

        {svgStage}
      </div>
    </div>
  );
}

export default SwanAnimation;